from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismTriggerCallbackNode(BaseNode):
    name = "Prism: Trigger Callback"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("callback_name", "string", widget_type="text", default="onShotCreated")
        self.add_input("args", "list")
        self.add_output("success", "bool")
        self.add_output("result", "any")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        name = inputs.get('callback_name') or ''
        args = inputs.get('args') or []
        if not isinstance(args, (list, tuple)):
            args = [args]
        if core is None or not name:
            self.log_error("Need PrismCore and callback_name.")
            return {'success': False, 'result': ''}
        try:
            cbs = core.callbacks
            fn = getattr(cbs, 'callback', None) or getattr(cbs, 'callBack', None) or getattr(cbs, 'trigger', None)
            if fn is None:
                self.log_error("No callback trigger method on core.callbacks.")
                return {'success': False, 'result': ''}
            result = fn(name, *args)
            self.log_success(f"Triggered callback '{name}' with {len(args)} arg(s).")
            await self.set_output('exec_out', True)
            return {'success': True, 'result': result if result is not None else ''}
        except Exception as e:
            self.log_error(f"trigger callback failed: {e}")
            return {'success': False, 'result': ''}

def register_node():
    return PrismTriggerCallbackNode
